# rebuild_project.py
# ==============================================================================
# SmartTravel - Automated Codebase Rebuilder & Environment Bootstrapper
# ==============================================================================
# This script contains the entire code, models, views, and test suites for the
# SmartTravel Flask web application. Running this script on any machine with
# Python 3 installed will automatically recreate the entire project directory
# structure, unpack all source files, set up migrations, and optionally install
# requirements.
# ==============================================================================

import os
import base64
import zlib
import sys
import subprocess

PROJECT_FILES = {'app.py': '', 'models.py': '', 'route_module.py': '', 'flight_serpapi.py': '', 'location_module.py': '', 'config/settings.py': '', 'config/constants.py': '', 'utils/helpers.py': '', 'utils/flight_helpers.py': '', 'modules/__init__.py': 'eJwDAAAAAAE=', 'modules/recommendation_engine.py': '', 'modules/bus_service.py': '', 'modules/bus_scraper.py': '', 'modules/train_module.py': '', 'templates/index.html': '', 'templates/plan.html': '', 'templates/bus.html': '', 'templates/results.html': '', 'templates/login_register.html': '', 'templates/error.html': '', 'README.md': '', 'AI_SYSTEM_SPEC.md': '', 'scratch/test_preferences.py': '', 'scratch/test_database.py': '', 'scratch/test_templates.py': ''}

def rebuild():
    print("======================================================================")
    print("                SmartTravel - Rebuilding Project                      ")
    print("======================================================================\n")
    
    current_dir = os.getcwd()
    print(f"Rebuilding project in: {current_dir}\n")
    
    # 1. Unpack all files and create directories
    for filepath, encoded_content in PROJECT_FILES.items():
        if not encoded_content:
            continue
            
        # Ensure directory path exists
        dirname = os.path.dirname(filepath)
        if dirname and not os.path.exists(dirname):
            os.makedirs(dirname, exist_ok=True)
            print(f"Created directory: {dirname}")
            
        # Decode and decompress content
        compressed_bytes = base64.b64decode(encoded_content.encode("ascii"))
        file_bytes = zlib.decompress(compressed_bytes)
        
        with open(filepath, "wb") as f:
            f.write(file_bytes)
        print(f"Unpacked: {filepath} ({len(file_bytes)} bytes)")
        
    print("\nProject files successfully unpacked!\n")
    
    # 2. Add sample datasets placeholders if they don't exist
    sample_files = {
        "airports.csv": "iata_code,name,latitude_deg,longitude_deg,iso_country\nIDR,Devi Ahilyabai Holkar Airport,22.7217,75.8015,IN\nBHO,Raja Bhoj International Airport,23.2875,77.3374,IN\nDEL,Indira Gandhi International Airport,28.5665,77.1031,IN\nBOM,Chhatrapati Shivaji Maharaj International Airport,19.0896,72.8656,IN\nGAU,Lokpriya Gopinath Bordoloi International Airport,26.1061,91.5859,IN\n",
        "all_india_stations_small.csv": "code,Station,Latitude,Longitude\nINDB,Indore Junction,22.7196,75.8577\nBPL,Bhopal Junction,23.2875,77.3374\nNDLS,New Delhi,28.6415,77.2201\nCSMT,Mumbai CSM Terminus,18.9400,72.8355\n",
        "final_junction1.csv": "code,Station,Latitude,Longitude\nINDB,Indore Junction,22.7196,75.8577\nBPL,Bhopal Junction,23.2875,77.3374\nNDLS,New Delhi,28.6415,77.2201\nCSMT,Mumbai CSM Terminus,18.9400,72.8355\n",
        "bus_schedules.csv": "route_id,source,destination,operator,bus_type,depart,duration,price,rating,punctuality\nBR-001,Indore,Bhopal,Chartered Bus,Volvo AC Sleeper,06:00,3.5,460,4.8,99\nBR-002,Delhi,Lucknow,NueGo Electric,AC Seater,08:30,6.0,850,4.6,95\n"
    }
    
    for filename, content in sample_files.items():
        if not os.path.exists(filename):
            with open(filename, "w", encoding="utf-8") as f:
                f.write(content)
            print(f"Created sample dataset: {filename}")

    print("\n======================================================================")
    print("Unpacking complete! Next Steps:")
    print("======================================================================")
    print("1. Set up a virtual environment: python -m venv .venv")
    print("2. Activate virtual environment: .venv\\Scripts\\activate (Windows)")
    print("3. Install packages: pip install flask flask-sqlalchemy flask-login flask-migrate folium requests pandas pyarrow fastparquet geopy geopy gunicorn undetected-chromedriver selenium")
    print("4. Initialize database: flask db init -> flask db migrate -> flask db upgrade")
    print("5. Run application: python app.py")
    print("======================================================================\n")

if __name__ == "__main__":
    rebuild()
